#!/usr/bin/env bash
# Remove the .tex / .md result tables generated by results_tables.ipynb.
# Safe to invoke from any directory - paths are resolved relative to this
# script's own location.

set -euo pipefail

DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"

FILES=(
	fullclass_results_table.tex
	fullclass_results_table.md
	subclass_results_table.tex
	subclass_results_table.md
	random_results_table.tex
	random_results_table.md
	pins_results_table.tex
	pins_results_table.md
	pins_raw_results_table.tex
	pins_raw_results_table.md
)

removed=0
for f in "${FILES[@]}"; do
	path="$DIR/$f"
	if [[ -f $path ]]; then
		rm -- "$path"
		echo "removed: $f"
		removed=$((removed + 1))
	fi
done

echo "done - removed $removed file(s)"
